class CountIntervals {
public:
    CountIntervals() {

    }

    void add(int left, int right) {
        if (intervals.empty() || left > intervals.rbegin()->first) {
            intervals[right] = left;
            count_ += right - left + 1;
        } else {
            auto it = intervals.lower_bound(left);
            if (it != intervals.begin()) {
                --it;
                if (it->second <= left) {
                    ++it;
                }
            }
            int newLeft = left, newRight = right;
            while (it != intervals.end() && it->second <= right) {
                newLeft = min(newLeft, it->second);
                newRight = max(newRight, it->first);
                count_ -= it->first - it->second + 1;
                it = intervals.erase(it);
            }
            if (it != intervals.end() && it->second <= newRight) {
                newLeft = min(newLeft, it->second);
                newRight = max(newRight, it->first);
                count_ -= it->first - it->second + 1;
                intervals.erase(it);
            }
            intervals[newRight] = newLeft;
            count_ += newRight - newLeft + 1;
        }
    }

    int count() {
        return count_;
    }
private:
    map<int, int> intervals; // key is right boundary, value is left boundary
    int count_ = 0;
};

